pages.css:
.page-01 { width: 1242px; height: 1660px; box-sizing: border-box; background-color: #F2F4F7; padding: 110px 100px; display: flex; flex-direction: column; position: relative; font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif; letter-spacing: 0; color: #101828; }
.page-header { display: flex; align-items: center; gap: 20px; margin-bottom: 140px; }
.header-icon { font-size: 44px; }
.header-label { font-size: 38px; color: #475467; font-weight: 600; letter-spacing: 0; }
.title-section { display: flex; flex-direction: column; gap: 28px; }
.page-title { font-size: 132px; line-height: 1.15; font-weight: 900; color: #101828; margin: 0; letter-spacing: 0; }
.content-section { margin-top: auto; display: flex; flex-direction: column; gap: 64px; }
.sub-item { display: flex; flex-direction: column; gap: 20px; border-top: 3px solid #D0D5DD; padding-top: 36px; }
.sub-tag { font-size: 34px; font-weight: 800; color: #E31B54; background-color: #FFE4E8; padding: 10px 20px; border-radius: 8px; width: fit-content; letter-spacing: 0; }
.sub-text { font-size: 42px; line-height: 1.6; color: #344054; margin: 0; font-weight: 400; letter-spacing: 0; }

.page-02 {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  background-color: #FFFFFF;
  padding: 88px 96px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  color: #111111;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 48px;
}

.page-label {
  font-size: 38px;
  color: #888888;
  font-weight: 600;
  letter-spacing: 0;
  text-transform: uppercase;
}

.page-icon {
  font-size: 46px;
}

.title-section {
  margin-bottom: 56px;
}

.page-title {
  font-size: 104px;
  font-weight: 900;
  line-height: 1.25;
  color: #111111;
  letter-spacing: 0;
}

.highlight-section {
  background-color: #F8F9FA;
  border-radius: 12px;
  padding: 40px 48px;
  margin-bottom: 60px;
  border-left: 12px solid #E63946;
}

.highlight-value {
  font-size: 112px;
  font-weight: 900;
  color: #E63946;
  line-height: 1.1;
  margin-bottom: 12px;
  letter-spacing: 0;
}

.highlight-sub {
  font-size: 42px;
  font-weight: 600;
  color: #333333;
  letter-spacing: 0;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 36px;
  flex: 1;
}

.proof-item {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.proof-tag {
  font-size: 38px;
  font-weight: 800;
  color: #111111;
  letter-spacing: 0;
  display: flex;
  align-items: center;
}

.proof-tag::before {
  content: "";
  display: inline-block;
  width: 12px;
  height: 12px;
  background-color: #E63946;
  margin-right: 16px;
}

.proof-text {
  font-size: 42px;
  line-height: 1.6;
  color: #444444;
  letter-spacing: 0;
}

.page-footnote {
  margin-top: auto;
  padding-top: 32px;
  font-size: 36px;
  color: #999999;
  line-height: 1.5;
  border-top: 2px solid #EEEEEE;
  letter-spacing: 0;
}

.page-04 {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  padding: 100px;
  background-color: #F7F8FA;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
}
.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 60px;
}
.header-icon {
  font-size: 44px;
}
.header-label {
  font-size: 38px;
  color: #888888;
  font-weight: 600;
  letter-spacing: 0;
}
.title-section {
  margin-bottom: 80px;
}
.page-title {
  font-size: 104px;
  font-weight: 900;
  line-height: 1.25;
  color: #1A1A1A;
  margin: 0;
  letter-spacing: 0;
}
.list-section {
  display: flex;
  flex-direction: column;
  gap: 32px;
}
.list-item {
  background: #FFFFFF;
  border-radius: 16px;
  padding: 40px 48px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.02);
  border-left: 8px solid #2B5CFF;
}
.item-tag {
  font-size: 36px;
  font-weight: 800;
  color: #2B5CFF;
  margin-bottom: 20px;
  letter-spacing: 0;
  display: inline-block;
  background: rgba(43,92,255,0.08);
  padding: 8px 24px;
  border-radius: 8px;
}
.item-text {
  font-size: 40px;
  line-height: 1.55;
  color: #333333;
  margin: 0;
  letter-spacing: 0;
}

.page-05 {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  background-color: #0F172A;
  color: #F8FAFC;
  padding: 120px 100px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 80px;
}

.header-icon {
  font-size: 46px;
}

.header-label {
  font-size: 38px;
  font-weight: 500;
  color: #94A3B8;
}

.page-title {
  margin-bottom: 100px;
}

.title-line {
  font-size: 100px;
  font-weight: 800;
  line-height: 1.35;
  color: #FFFFFF;
}

.action-list {
  display: flex;
  flex-direction: column;
  gap: 64px;
}

.action-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
  border-left: 8px solid #38BDF8;
  padding-left: 36px;
}

.action-tag {
  font-size: 44px;
  font-weight: 700;
  color: #38BDF8;
}

.action-text {
  font-size: 40px;
  line-height: 1.6;
  color: #CBD5E1;
}
